import React from 'react';

const VirtualKeyboard = ({ activeKey }) => {
  // Finger mapping for color coding
  const fingerMap = {
    '`': 'left-pinky', '1': 'left-pinky', 'q': 'left-pinky', 'a': 'left-pinky', 'z': 'left-pinky',
    '2': 'left-ring', 'w': 'left-ring', 's': 'left-ring', 'x': 'left-ring',
    '3': 'left-middle', 'e': 'left-middle', 'd': 'left-middle', 'c': 'left-middle',
    '4': 'left-index', '5': 'left-index', 'r': 'left-index', 't': 'left-index', 
    'f': 'left-index', 'g': 'left-index', 'v': 'left-index', 'b': 'left-index',
    '6': 'right-index', '7': 'right-index', 'y': 'right-index', 'u': 'right-index',
    'h': 'right-index', 'j': 'right-index', 'n': 'right-index', 'm': 'right-index',
    '8': 'right-middle', 'i': 'right-middle', 'k': 'right-middle', ',': 'right-middle',
    '9': 'right-ring', 'o': 'right-ring', 'l': 'right-ring', '.': 'right-ring',
    '0': 'right-pinky', '-': 'right-pinky', '=': 'right-pinky',
    'p': 'right-pinky', '[': 'right-pinky', ']': 'right-pinky', '\\': 'right-pinky',
    ';': 'right-pinky', "'": 'right-pinky', '/': 'right-pinky'
  };

  const keyboardLayout = [
    ['`', '1', '2', '3', '4', '5', '6', '7', '8', '9', '0', '-', '=', 'BACKSPACE'],
    ['TAB', 'q', 'w', 'e', 'r', 't', 'y', 'u', 'i', 'o', 'p', '[', ']', '\\'],
    ['CAPS', 'a', 's', 'd', 'f', 'g', 'h', 'j', 'k', 'l', ';', "'", 'ENTER'],
    ['SHIFT_L', 'z', 'x', 'c', 'v', 'b', 'n', 'm', ',', '.', '/', 'SHIFT_R'],
    ['SPACE']
  ];

  const isKeyActive = (key) => {
    if (!activeKey) return false;

    if (key === 'SPACE' && activeKey === ' ') return true;
    if (key === 'ENTER' && activeKey === 'Enter') return true;
    if (key === 'BACKSPACE' && activeKey === 'Backspace') return true;
    if (key === 'TAB' && activeKey === 'Tab') return true;
    if (key === 'CAPS' && activeKey === 'CapsLock') return true;
    if ((key === 'SHIFT_L' || key === 'SHIFT_R') && activeKey === 'Shift') return true;

    return key.toLowerCase() === activeKey.toLowerCase();
  };

  return (
    <div className="virtual-keyboard">
      <h3 style={{ textAlign: 'center', marginBottom: '1rem', color: '#667eea' }}>
        Virtual Keyboard
      </h3>
      {keyboardLayout.map((row, rowIndex) => (
        <div key={rowIndex} className="keyboard-row">
          {row.map((key) => {
            const specialClasses = [];
            if (key === 'SPACE') specialClasses.push('space');
            if (key === 'SHIFT_L' || key === 'SHIFT_R') specialClasses.push('shift');
            if (key === 'ENTER') specialClasses.push('enter');
            if (key === 'BACKSPACE') specialClasses.push('backspace');
            if (key === 'TAB') specialClasses.push('tab');
            if (key === 'CAPS') specialClasses.push('caps');

            // Add finger color class
            const fingerClass = fingerMap[key] || '';
            if (fingerClass) specialClasses.push(fingerClass);

            const getLabel = (k) => {
              if (k === 'SPACE') return 'Space';
              if (k === 'SHIFT_L' || k === 'SHIFT_R') return 'Shift';
              if (k === 'ENTER') return 'Enter';
              if (k === 'BACKSPACE') return '⌫';
              if (k === 'TAB') return 'Tab';
              if (k === 'CAPS') return 'Caps';
              return k;
            };

            return (
              <div
                key={key}
                className={`key ${specialClasses.join(' ')} ${isKeyActive(key) ? 'active' : ''}`}
              >
                {getLabel(key)}
              </div>
            );
          })}
        </div>
      ))}
      <div style={{ textAlign: 'center', marginTop: '1rem', color: '#666', fontSize: '0.9rem' }}>
        <p>Keep your fingers on the home row: A S D F | J K L ;</p>
      </div>
    </div>
  );
};

export default VirtualKeyboard;
